static void print_mp(FILE*f,mpfr_t x){ mpfr_out_str(f,10,18,x,MPFR_RNDN); }
static void u(FILE*f,sda_u128 v){ char b[64]; sda_print_u128(v,b,sizeof b); fputs(b,f); }
static void uexpr(FILE*f,sda_u128 v){ if(v <= (sda_u128)18446744073709551615ULL){ fprintf(f,"(sda_u128)"); u(f,v); fprintf(f,"ULL"); } else { sda_u128 hi=v/1000u, lo=v%1000u; fprintf(f,"((sda_u128)"); u(f,hi); fprintf(f,"ULL*1000u+(sda_u128)%luu)",(unsigned long)lo); } }
static void arr(FILE*f,const char*name,const sda_u128*a,size_t n){ fprintf(f,"static const sda_u128 %s[]={",name); for(size_t i=0;i<n;i++){ if(i)fputc(',',f); uexpr(f,a[i]); } fprintf(f,"};\n"); }
static unsigned long hcfg(const sda_config*c){ unsigned long h=1469598103u; const unsigned char*p=(const unsigned char*)c; for(size_t i=0;i<sizeof*c;i++) h=(h^p[i])*16777619u; return h; }
static int one(const char*path,const char*solver,sda_generation_result*r){ sda_config c; if(sda_config_load(path,&c)){perror(path);return 1;} if(!*c.parameter_set){ const char*s=strrchr(path,'/'); snprintf(c.parameter_set,sizeof c.parameter_set,"%s",s?s+1:path); char*d=strchr(c.parameter_set,'.'); if(d)*d=0; } sda_generation_result_init(r,c.mpfr_precision); int rc=sda_generate_for_config(&c,solver,r); if(rc){ fprintf(stderr,"generation failed for %s solver=%s status=%d (%s)\n",path,solver,rc,sda_lll_status()); sda_generation_result_clear(r); return 1; } r->source_is_fixture=0; return 0; }
static int write_outputs(sda_generation_result*r,const char**names,size_t m,int reproducible){ FILE*h=fopen("generated/sda_generated_tables.h","w"); FILE*csv=fopen("generated/sda_tables.csv","w"); FILE*met=fopen("generated/sda_metrics.csv","w"); FILE*rep=fopen("generated/sda_generation_report.txt","w"); FILE*cand=fopen("generated/sda_candidate_report.csv","w"); if(!h||!csv||!met||!rep||!cand)return 1; time_t now=time(NULL); fprintf(h,"#ifndef SDA_GENERATED_TABLES_H\n#define SDA_GENERATED_TABLES_H\n#include \"sda_table.h\"\n#define SDA_GENERATED_VERSION \"auto-generated-v2\"\n#define SDA_GENERATED_SOURCE_IS_FIXTURE 0\n"); fprintf(csv,"parameter_set,q,probability_masses,cumulative_thresholds\n"); fprintf(met,"parameter_set,solver,solver_exact,solver_heuristic,source_is_fixture,q,q_bitlength,tail_mass,sd_infinite,log2_sd,renyi,log2_renyi_minus_one,fixed_packed_bits,cumulative_native_bytes,generation_time\n"); fprintf(cand,"parameter_set,q,q_bitlength,max_scaled_error,max_absolute_error,SD,RD,log2_RD_minus_one\n"); fprintf(rep,"generation_mode=production-auto\nsource_is_fixture=false\ngeneration_timestamp=%s\nGMP version=%s\nMPFR version=%s\nFLINT status=%s\nselection_rule=min bitlength, min q, min SD, min E_inf, lexicographic p\n",reproducible?"reproducible":ctime(&now),gmp_version,mpfr_get_version(),sda_lll_status()); for(size_t i=0;i<m;i++){ char pn[64],cn[64]; snprintf(pn,sizeof pn,"sda_%s_p",names[i]); snprintf(cn,sizeof cn,"sda_%s_c",names[i]); arr(h,pn,r[i].p,r[i].n); arr(h,cn,r[i].c,r[i].n); fprintf(csv,"%s,",names[i]); u(csv,r[i].q); fprintf(csv,",\""); for(size_t j=0;j<r[i].n;j++){ if(j)fputc(' ',csv); u(csv,r[i].p[j]); } fprintf(csv,"\",\""); for(size_t j=0;j<r[i].n;j++){ if(j)fputc(' ',csv); u(csv,r[i].c[j]); } fprintf(csv,"\"\n"); fprintf(met,"%s,%s,%d,%d,%d,",names[i],r[i].solver,r[i].exact,r[i].heuristic,r[i].source_is_fixture); u(met,r[i].q); fprintf(met,",%d,",r[i].q_bits); print_mp(met,r[i].tail_mass); fputc(',',met); print_mp(met,r[i].sd_infinite); fputc(',',met); print_mp(met,r[i].log2_sd); fputc(',',met); print_mp(met,r[i].renyi); fputc(',',met); print_mp(met,r[i].log2_renyi_minus_one); fprintf(met,",%zu,%zu,%.6f\n",r[i].n*(size_t)r[i].q_bits,r[i].n*sizeof(sda_u128),r[i].generation_time); fprintf(cand,"%s,",names[i]); u(cand,r[i].q); fprintf(cand,",%d,",r[i].q_bits); print_mp(cand,r[i].max_scaled_error); fputc(',',cand); print_mp(cand,r[i].max_abs_error); fputc(',',cand); print_mp(cand,r[i].sd_infinite); fputc(',',cand); print_mp(cand,r[i].renyi); fputc(',',cand); print_mp(cand,r[i].log2_renyi_minus_one); fputc('\n',cand); fprintf(rep,"\n[%s]\nsolver=%s\nsource_is_fixture=false\nq=",names[i],r[i].solver); u(rep,r[i].q); fprintf(rep,"\nq_bitlength=%d\ngaussian_s=",r[i].q_bits); print_mp(rep,r[i].gaussian_s); fprintf(rep,"\ntail_mass="); print_mp(rep,r[i].tail_mass); fprintf(rep,"\nSD="); print_mp(rep,r[i].sd_infinite); fprintf(rep,"\nRD="); print_mp(rep,r[i].renyi); fprintf(rep,"\nlog2_RD_minus_one="); print_mp(rep,r[i].log2_renyi_minus_one); fprintf(rep,"\ndenominators_scanned=%lu\n",r[i].denominators_scanned); }
 fprintf(h,"static const sda_table sda_generated_tables[]={\n"); for(size_t i=0;i<m;i++){ fprintf(h,"{\"%s\",\"%s\",\"%s\",0,%zu,%d,%d,%d,0,%zu,", strstr(names[i],"falcon")?"Falcon":"Frodo",names[i],r[i].solver,r[i].n-1,r[i].q_bits,r[i].exact,r[i].heuristic,r[i].n); uexpr(h,r[i].q); fprintf(h,",sda_%s_p,sda_%s_c,%zu,%zu}%s\n",names[i],names[i],2*r[i].n*sizeof(sda_u128),r[i].n*(size_t)r[i].q_bits,i+1<m?",":""); } fprintf(h,"};\nstatic const size_t sda_generated_tables_count=%zu;\n#endif\n",m); fclose(h); fclose(csv); fclose(met); fclose(rep); fclose(cand); return 0; }
int main(int argc,char**argv){ int all=0,repro=0; const char*cfg=NULL; const char*solver=NULL; for(int i=1;i<argc;i++){ if(!strcmp(argv[i],"--all"))all=1; else if(!strcmp(argv[i],"--reproducible"))repro=1; else if(!strcmp(argv[i],"--config")&&i+1<argc)cfg=argv[++i]; else if(!strcmp(argv[i],"--solver")&&i+1<argc)solver=argv[++i]; else if(!strcmp(argv[i],"--target-q")){fprintf(stderr,"target-q is nonproduction; refusing without --allow-nonproduction-output\n"); return 2;} }
 sda_generation_result r[4]; const char*names[4]={"frodo640","frodo976","frodo1344","falcon"}; const char*paths[4]={"config/frodo640.conf","config/frodo976.conf","config/frodo1344.conf","config/falcon.conf"}; const char*solv[4]={"exact-denominator","exact-denominator","exact-denominator","flint-lll"}; size_t m=0; if(all){ for(size_t i=0;i<4;i++){ if(one(paths[i],solv[i],&r[i])) return 1; m++; } } else { if(!cfg||!solver){fprintf(stderr,"usage: generate_sdat --all | --config file --solver exact-denominator|flint-lll\n"); return 2;} if(one(cfg,solver,&r[0])) return 1; names[0]=strstr(cfg,"falcon")?"falcon":strstr(cfg,"976")?"frodo976":strstr(cfg,"1344")?"frodo1344":"frodo640"; m=1; }
 if(write_outputs(r,names,m,repro)) return 1; for(size_t i=0;i<m;i++) sda_generation_result_clear(&r[i]); puts("generated production tables from distribution parameters; source_is_fixture=false"); return 0; }
